Theorem lt_ropt `{Funext}
        {L R : Type@{i}} {s : InSort S L R}
        (xL : L -> No) (xR : R -> No)
        (xcut : forall (l:L) (r:R), (xL l) < (xR r))
        (r : R)
: {{ xL | xR // xcut }} < xR r.

